import{R as e,S as t,x as n}from"./vue-DN8T-JnG.js";import{Jr as r}from"./common-Dj5H8TAk.js";import"./self-evolving-Dp2Jjcwq.js";var i=JSON.parse(`{"path":"/article/pri-tpg-structural-priors/","title":"LLMs Don't Lack More Knowledge, But Reasoning Structures: A Close Reading of Pri-TPG | Blog","lang":"en-US","frontmatter":{"author":"Kstheme","date":"2025-11-10T00:00:00.000Z","category":["Paper Review"],"tags":["pri-tpg","llm","theorem-proving","paper"],"title":"LLMs Don't Lack More Knowledge, But Reasoning Structures: A Close Reading of Pri-TPG","createTime":"2026/07/17 21:58:42","permalink":"/article/pri-tpg-structural-priors/","description":"From content retrieval to structure retrieval — a training-free long-range reasoning approach. Large language models exhibit a paradoxical behavior when solving mathematical pro...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"LLMs Don't Lack More Knowledge, But Reasoning Structures: A Close Reading of Pri-TPG\\",\\"image\\":[\\"https://kstheme.github.io/images/pri-tpg/structural-drift.png\\",\\"https://kstheme.github.io/images/pri-tpg/state-transition.png\\",\\"https://kstheme.github.io/images/pri-tpg/flat-vs-structured.png\\",\\"https://kstheme.github.io/images/pri-tpg/workflow.png\\",\\"https://kstheme.github.io/images/pri-tpg/three-layer-prior.png\\",\\"https://kstheme.github.io/images/pri-tpg/singlepass-vs-iterative.png\\",\\"https://kstheme.github.io/images/pri-tpg/experiment-chain.png\\",\\"https://kstheme.github.io/images/pri-tpg/self-evolving.png\\"],\\"datePublished\\":\\"2025-11-10T00:00:00.000Z\\",\\"dateModified\\":\\"2026-07-20T00:36:25.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kstheme\\"}]}"],["meta",{"property":"og:url","content":"https://kstheme.github.io/article/pri-tpg-structural-priors/"}],["meta",{"property":"og:site_name","content":"Kstheme"}],["meta",{"property":"og:title","content":"LLMs Don't Lack More Knowledge, But Reasoning Structures: A Close Reading of Pri-TPG"}],["meta",{"property":"og:description","content":"From content retrieval to structure retrieval — a training-free long-range reasoning approach. Large language models exhibit a paradoxical behavior when solving mathematical pro..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kstheme.github.io/images/pri-tpg/structural-drift.png"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:locale:alternate","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-20T00:36:25.000Z"}],["meta",{"property":"article:author","content":"Kstheme"}],["meta",{"property":"article:tag","content":"paper"}],["meta",{"property":"article:tag","content":"theorem-proving"}],["meta",{"property":"article:tag","content":"llm"}],["meta",{"property":"article:tag","content":"pri-tpg"}],["meta",{"property":"article:published_time","content":"2025-11-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-20T00:36:25.000Z"}],["link",{"rel":"alternate","hreflang":"zh-cn","href":"https://kstheme.github.io/zh/article/pri-tpg-structural-priors/"}]]},"readingTime":{"minutes":13.45,"words":4034},"git":{"createdTime":1784297561000,"updatedTime":1784507785000,"contributors":[{"name":"Alan Zero","username":"","email":"342200758@qq.com","commits":3,"avatar":"https://gravatar.com/avatar/b561d338c9388496bb60e370ebefeafdbbfef58821683e39b3fa9e070269f832?d=retro"}]},"autoDesc":true,"filePathRelative":"blog/Paper/pri-tpg-structural-priors.md","headers":[],"categoryList":[{"id":"d0a662","sort":10004,"name":"Paper"}]}`),a={name:`pri-tpg-structural-priors.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<blockquote><p>From content retrieval to structure retrieval — a training-free long-range reasoning approach.</p></blockquote><p>Large language models exhibit a paradoxical behavior when solving mathematical proofs:</p><p><strong>As problems grow longer, model performance doesn&#39;t just gradually decline — it rapidly collapses.</strong></p><p>On the FormalGeo7K geometry reasoning benchmark, Vanilla ICL achieves 52.19% accuracy on shallow L1 problems, but drops to just 7.89% on L3. On longer L5 and L6 reasoning tasks, accuracy falls directly to 0.</p><p>After introducing structural priors, Pri-TPG using the same GPT-5 mini improves overall accuracy from 26.29% to 84.42%. With GPT-5.2, it reaches 89.29%.</p><p>The paper calls this phenomenon where standard ICL rapidly fails as reasoning depth increases:</p><blockquote><p><strong>Structural Drift.</strong></p></blockquote><p>This concept reveals an important problem:</p><blockquote><p>LLMs may know what each theorem means, but they don&#39;t know the order in which these theorems should be organized.</p></blockquote><p>A more specific question emerges:</p><blockquote><p>Can we avoid updating model parameters, and instead provide the LLM with an external structure that guides it to search only along more promising proof paths?</p></blockquote><p>This is the problem that the paper <strong>Non-Parametric Structural Priors for Geometry Theorem Prediction</strong> aims to solve.</p><figure><img src="/images/pri-tpg/structural-drift.png" alt="" tabindex="0" loading="lazy" width="798" height="443"><figcaption></figcaption></figure><h1 id="paper-information-card" tabindex="-1"><a class="header-anchor" href="#paper-information-card"><span>Paper Information Card</span></a></h1><table><thead><tr><th>Item</th><th>Content</th></tr></thead><tbody><tr><td>Paper Title</td><td>Non-Parametric Structural Priors for Geometry Theorem Prediction</td></tr><tr><td>Core Method</td><td>Pri-TPG</td></tr><tr><td>Research Task</td><td>Multi-step geometry theorem prediction</td></tr><tr><td>Technical Approach</td><td>RAG + Theorem Precedence Graph + Symbolic Execution</td></tr><tr><td>Key Feature</td><td>Training-free — no gradient training required for theorem prediction</td></tr><tr><td>Main Datasets</td><td>FormalGeo7K, Geometry3K, GeoQA</td></tr><tr><td>Main Result</td><td>89.29% on FormalGeo7K</td></tr><tr><td>Keywords</td><td>Structural Drift, Structural Prior, LLM Planner, Neural-Symbolic Reasoning</td></tr></tbody></table><p>One-sentence summary:</p><blockquote><p>Pri-TPG doesn&#39;t directly retrieve answers — it retrieves proof structures from similar problems, then uses these structures to constrain the LLM&#39;s next action.</p></blockquote><h2 id="_01-why-is-geometry-theorem-proving-essentially-a-search-problem" tabindex="-1"><a class="header-anchor" href="#_01-why-is-geometry-theorem-proving-essentially-a-search-problem"><span>01. Why Is Geometry Theorem Proving Essentially a Search Problem?</span></a></h2><p>A geometry problem that seems straightforward to a human is often not a single-step Q&amp;A for an automated reasoning system, but a continuous decision process.</p><p>For example, a complete proof might require:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Prove two sides are equal</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Determine triangle congruence</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Derive corresponding angle equality</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Construct similar triangles</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Derive the target ratio</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The key isn&#39;t just &quot;selecting the correct theorem.&quot;</p><p>More importantly:</p><p><strong>The currently selected theorem must be grounded in facts already established.</strong></p><p>If a theorem&#39;s prerequisites haven&#39;t been satisfied, it cannot be executed — even if it&#39;s semantically relevant to the target.</p><p>Formally, a geometry problem can be described as:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Initial state S₀</span></span>
<span class="line"><span>↓ Apply theorem a₁</span></span>
<span class="line"><span>State S₁</span></span>
<span class="line"><span>↓ Apply theorem a₂</span></span>
<span class="line"><span>State S₂</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>……</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Final state Sₜ satisfies goal g</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A symbolic executor can check whether each step is valid, but it cannot automatically tell the model:</p><blockquote><p>Among hundreds of theorems, which one should be chosen next?</p></blockquote><p>Assume a theorem library of 300 theorems and a proof requiring H steps. In the most naive case, the search space approaches:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>300ᴴ</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>The longer the reasoning chain, the more erroneous branches exist.</p><p>Therefore, the difficulty of geometry proving is not just insufficient knowledge — it&#39;s:</p><blockquote><p><strong>How to continuously find valid next steps among an exponentially growing set of candidate paths.</strong></p></blockquote><figure><img src="/images/pri-tpg/state-transition.png" alt="" tabindex="0" loading="lazy" width="1200" height="896"><figcaption></figcaption></figure><h2 id="_02-structural-drift-knowing-theorems-but-not-proof-structure" tabindex="-1"><a class="header-anchor" href="#_02-structural-drift-knowing-theorems-but-not-proof-structure"><span>02. Structural Drift: Knowing Theorems but Not Proof Structure</span></a></h2><p>The most straightforward approach is In-Context Learning.</p><p>Give the LLM a few example proofs and let it imitate them to select theorems step by step.</p><p>But the paper finds that Vanilla ICL, while effective on shallow problems, rapidly collapses as proof length increases.</p><p>The authors attribute this to the fact that standard ICL provides &quot;content examples&quot; but no explicit &quot;structural constraints.&quot;</p><table><thead><tr><th>What the LLM may know</th><th>What the LLM may not know about structure</th></tr></thead><tbody><tr><td>What the Pythagorean theorem is</td><td>Whether its prerequisites are satisfied now</td></tr><tr><td>All triangle congruence criteria</td><td>Which criterion should be applied first</td></tr><tr><td>Which theorems relate to angles vs. lengths</td><td>Which theorems are inexecutable in the current state</td></tr><tr><td>Which theorems are semantically related to the goal</td><td>Whether a theorem lies on a valid proof path</td></tr><tr><td>How to generate the next explanation</td><td>Which branch to switch to after failure</td></tr></tbody></table><p>The problem can be compressed into two sentences:</p><blockquote><p><strong>A theorem being semantically relevant doesn&#39;t mean it&#39;s executable in the current state.</strong><strong>Selecting locally correct steps doesn&#39;t mean maintaining a globally coherent proof structure.</strong></p></blockquote><p>Standard ICL is like making flat selections across the entire theorem library.</p><p>With each step facing a large set of candidates, early small errors compound and eventually derail the entire proof path.</p><p>This is Structural Drift.</p><figure><img src="/images/pri-tpg/flat-vs-structured.png" alt="" tabindex="0" loading="lazy" width="1200" height="896"><figcaption></figcaption></figure><h2 id="_03-pri-tpg-retrieving-not-knowledge-but-proof-structure" tabindex="-1"><a class="header-anchor" href="#_03-pri-tpg-retrieving-not-knowledge-but-proof-structure"><span>03. Pri-TPG: Retrieving Not Knowledge, but Proof Structure</span></a></h2><p>What does traditional RAG typically do?</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Input a question</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Retrieve relevant text or knowledge</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Include in the prompt</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Let the LLM generate an answer</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>It addresses:</p><blockquote><p>What should the model know?</p></blockquote><p>Pri-TPG works differently.</p><p>It retrieves historical geometry problems similar to the current one, then extracts from their proof traces:</p><ul><li>Which theorems appear frequently;</li><li>Which theorems typically appear first;</li><li>Which theorems usually follow others;</li><li>Which local reasoning structures may apply to the current problem.</li></ul><p>Thus, Pri-TPG is closer to:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Input a question</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Retrieve similar proofs</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Extract theorem usage order</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Build a theorem precedence graph</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Constrain the next reasoning step</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The difference can be summarized as:</p><table><thead><tr><th>Traditional RAG</th><th>Pri-TPG</th></tr></thead><tbody><tr><td>Retrieves facts, passages, documents</td><td>Retrieves historical proof traces</td></tr><tr><td>Answers &quot;what to know&quot;</td><td>Answers &quot;what to do first, what to do next&quot;</td></tr><tr><td>Results added to prompt as text</td><td>Results transformed into graph structure</td></tr><tr><td>Primarily augments content</td><td>Primarily constrains action space</td></tr><tr><td>Content-Augmented</td><td>Structure-Augmented</td></tr></tbody></table><p>Therefore, Pri-TPG&#39;s key insight isn&#39;t simply adding more retrieval — it&#39;s:</p><blockquote><p><strong>Transforming retrieval results from &quot;content context&quot; into &quot;reasoning structure.&quot;</strong></p></blockquote><h2 id="_04-what-is-the-theorem-precedence-graph" tabindex="-1"><a class="header-anchor" href="#_04-what-is-the-theorem-precedence-graph"><span>04. What Is the Theorem Precedence Graph?</span></a></h2><p>Pri-TPG&#39;s core structure is the:</p><blockquote><p><strong>Theorem Precedence Graph (TPG).</strong></p></blockquote><p>It&#39;s a directed graph.</p><table><thead><tr><th>Graph Element</th><th>Meaning</th></tr></thead><tbody><tr><td>Node (v)</td><td>A theorem</td></tr><tr><td>Edge (<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mi>u</mi><mo>→</mo><mi>v</mi></mrow><annotation encoding="application/x-tex">u \\rightarrow v</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.4306em;"></span><span class="mord mathnormal">u</span><span class="mspace" style="margin-right:0.2778em;"></span><span class="mrel">→</span><span class="mspace" style="margin-right:0.2778em;"></span></span><span class="base"><span class="strut" style="height:0.4306em;"></span><span class="mord mathnormal" style="margin-right:0.0359em;">v</span></span></span></span>)</td><td>Theorem u produces results that support using theorem v</td></tr><tr><td>Edge weight</td><td>Frequency of this theorem transition in similar historical proofs</td></tr><tr><td>START node</td><td>Theorems more likely to be used first at the start of a proof</td></tr></tbody></table><p>For example, a local path might be:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Isosceles triangle判定</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Isosceles triangle properties</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Angle equality</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Similar triangle判定</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Instead of choosing from 300 theorems arbitrarily, TPG tells the model:</p><blockquote><p>Now that you&#39;ve just used a certain theorem, the more reasonable next candidates are typically its successors in the graph.</p></blockquote><p>TPG is not a fixed proof chain.</p><p>It&#39;s more like a local navigation map:</p><table><thead><tr><th>Fixed Proof Chain</th><th>TPG</th></tr></thead><tbody><tr><td>Must follow a single path</td><td>Can retain multiple feasible successors</td></tr><tr><td>Close to template replication</td><td>Closer to structural constraints</td></tr><tr><td>Sensitive to variation</td><td>Allows the LLM to choose within a local graph</td></tr><tr><td>Lacks flexibility</td><td>Preserves some planning freedom</td></tr></tbody></table><p>The paper notes that in FormalGeo7K experiments, after candidate filtering, the number of theorems per step is reduced from roughly 300 to about 30 — approximately a 90% reduction in single-step search space.</p><h2 id="_05-pri-tpg-doesn-t-use-just-a-single-static-graph" tabindex="-1"><a class="header-anchor" href="#_05-pri-tpg-doesn-t-use-just-a-single-static-graph"><span>05. Pri-TPG Doesn&#39;t Use Just a Single Static Graph</span></a></h2><p>If we simply count theorem order across all historical proofs and build one global graph, there&#39;s an obvious problem:</p><blockquote><p>Different problems require different theorem structures.</p></blockquote><p>Circles, triangles, parallelograms, length calculations, angle proofs — each has very different proof paths.</p><p>Therefore, Pri-TPG refines structural priors layer by layer.</p><figure><img src="/images/pri-tpg/workflow.png" alt="" tabindex="0" loading="lazy" width="2069" height="934"><figcaption></figcaption></figure><p><em>Starting from the global theorem library, the system progressively narrows the search space to the set of theorems most likely valid in the current state through retrieval, graph construction, and symbolic verification.</em></p><h3 id="three-layers-of-structural-priors" tabindex="-1"><a class="header-anchor" href="#three-layers-of-structural-priors"><span>Three Layers of Structural Priors</span></a></h3><table><thead><tr><th>Layer</th><th>Input</th><th>Main Operation</th><th>Problem Solved</th></tr></thead><tbody><tr><td>Global Prior</td><td>All historical proof traces</td><td>Statistics of global theorem precedence</td><td>Establishes domain-level structure</td></tr><tr><td>Query-Adaptive Prior</td><td>Current problem and similar historical problems</td><td>Build problem-related candidate pool and local TPG</td><td>Eliminates theorems irrelevant to the current problem</td></tr><tr><td>State-Aware Prior</td><td>Current symbolic state and previous action</td><td>Symbolic pruning, structural localization, candidate ranking</td><td>Eliminates inexecutable or structurally unreasonable actions</td></tr></tbody></table><h3 id="layer-1-global-prior" tabindex="-1"><a class="header-anchor" href="#layer-1-global-prior"><span>Layer 1: Global Prior</span></a></h3><p>The global prior comes from all historical proof traces.</p><p>It answers:</p><blockquote><p>In the entire dataset, which theorems frequently have precedence relationships?</p></blockquote><p>This layer provides domain-level structure.</p><p>But it&#39;s too broad — the global graph contains many theorems irrelevant to the current problem.</p><h3 id="layer-2-query-adaptive-prior" tabindex="-1"><a class="header-anchor" href="#layer-2-query-adaptive-prior"><span>Layer 2: Query-Adaptive Prior</span></a></h3><p>Pri-TPG retrieves similar historical problems based on the current problem.</p><p>Retrieval conditions include:</p><table><thead><tr><th>Input Modality</th><th>Role</th></tr></thead><tbody><tr><td>Problem text</td><td>Captures semantics and goal type</td></tr><tr><td>Geometry image</td><td>Captures图形 structure</td></tr><tr><td>Initial formalized state</td><td>Captures already established symbolic facts</td></tr></tbody></table><p>The system uses multimodal encoders to map this information into a unified vector space, then retrieves Top-K similar problems from the training set.</p><p>Next, it extracts the theorems used in these similar problems and merges their corresponding TPGs to form a problem-specific:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Candidate theorem set Lq</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Query-relative graph Gq</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This layer answers:</p><blockquote><p>For this specific problem, which theorem sequences are more likely useful?</p></blockquote><p>If a must-use theorem is missed during retrieval, no amount of LLM reasoning power can complete the proof later.</p><p>Results for different retrieval sizes:</p><table><thead><tr><th>Top-K</th><th>Total</th><th>Easy</th><th>Medium</th><th>Hard</th></tr></thead><tbody><tr><td>15</td><td>71.86</td><td>83.37</td><td>52.96</td><td>28.69</td></tr><tr><td>30</td><td>79.00</td><td>94.39</td><td>61.64</td><td>30.33</td></tr><tr><td>100</td><td>80.29</td><td>95.32</td><td>64.30</td><td>30.33</td></tr><tr><td>200</td><td>84.42</td><td>96.14</td><td>73.05</td><td>40.98</td></tr></tbody></table><p>As K increases, overall performance steadily improves, especially on medium and hard problems. Long-chain proofs require recalling more specialized theorems — if a critical theorem is missed, subsequent planning cannot succeed.</p><h3 id="layer-3-state-aware-prior" tabindex="-1"><a class="header-anchor" href="#layer-3-state-aware-prior"><span>Layer 3: State-Aware Prior</span></a></h3><p>Even if a theorem appears in similar problems, it may not be usable right now.</p><p>Therefore, Pri-TPG continues to prune based on the current state at each step.</p><table><thead><tr><th>Mechanism</th><th>Approach</th><th>Role</th></tr></thead><tbody><tr><td>Symbolic Pruning</td><td>Check whether candidate theorem prerequisites are satisfied</td><td>Eliminates mathematically inexecutable actions</td></tr><tr><td>Structural Localization</td><td>Prioritize successors of the previous theorem in the graph</td><td>Maintains local reasoning coherence</td></tr><tr><td>Candidate Prioritization</td><td>Rank based on goal, graph structure, and history</td><td>Presents higher-value candidates to the LLM first</td></tr></tbody></table><p>The system progressively narrows from:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Global theorem library</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Problem-relevant theorem set</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Currently executable theorems</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Structurally reasonable theorems</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="/images/pri-tpg/three-layer-prior.png" alt="" tabindex="0" loading="lazy" width="1200" height="896"><figcaption></figcaption></figure><h2 id="_06-what-do-the-llm-graph-and-symbolic-executor-each-handle" tabindex="-1"><a class="header-anchor" href="#_06-what-do-the-llm-graph-and-symbolic-executor-each-handle"><span>06. What Do the LLM, Graph, and Symbolic Executor Each Handle?</span></a></h2><p>Pri-TPG is neither a pure LLM system nor a pure symbolic search system.</p><p>It&#39;s a neural-symbolic closed loop.</p><table><thead><tr><th>Component</th><th>Role</th><th>Main Responsibility</th></tr></thead><tbody><tr><td>LLM</td><td>Planner</td><td>Selects the next theorem from candidates</td></tr><tr><td>TPG</td><td>Structural Prior</td><td>Provides theorem precedence, narrows action space</td></tr><tr><td>Symbolic Solver</td><td>Executor / Verifier</td><td>Checks prerequisites, executes theorems, updates state</td></tr><tr><td>Retrieval Module</td><td>Retriever</td><td>Recalls relevant proof structures from historical problems</td></tr><tr><td>Current State</td><td>Environment State</td><td>Records known facts and newly added facts</td></tr></tbody></table><p>The loop is:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>LLM selects a theorem</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Symbolic executor verifies and executes</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Update current state</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Re-filter graph and candidates based on new state</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>LLM selects again</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This closely resembles the typical Agent paradigm:</p><table><thead><tr><th>Agent Paradigm</th><th>Pri-TPG Component</th></tr></thead><tbody><tr><td>Think</td><td>LLM analyzes candidates</td></tr><tr><td>Act</td><td>Select a theorem</td></tr><tr><td>Environment Feedback</td><td>Symbolic executor returns results</td></tr><tr><td>Update State</td><td>Update symbolic facts</td></tr><tr><td>Replan</td><td>Re-select based on new state</td></tr></tbody></table><p>Thus, while the paper&#39;s task is geometry proving, it actually studies a more general Agent problem:</p><blockquote><p>How to enable LLMs to perform long-horizon planning in environments with large action spaces, strict rules, and clear feedback?</p></blockquote><h2 id="_07-candidates-are-not-simply-sorted-by-similarity" tabindex="-1"><a class="header-anchor" href="#_07-candidates-are-not-simply-sorted-by-similarity"><span>07. Candidates Are Not Simply Sorted by Similarity</span></a></h2><p>Pri-TPG doesn&#39;t just list retrieved theorems.</p><p>It ranks candidates based on three types of information:</p><table><thead><tr><th>Score Component</th><th>Meaning</th><th>Intuition</th></tr></thead><tbody><tr><td>(s_{goal})</td><td>Candidate&#39;s relevance to the final goal</td><td>Theorems closer to the goal ranked higher</td></tr><tr><td>(s_{graph})</td><td>Structural relationship to current graph position</td><td>Successors of the previous theorem ranked higher</td></tr><tr><td>(s_{hist})</td><td>Historical repetition and failure penalty</td><td>Avoid loops and repeated无效 attempts</td></tr></tbody></table><p>The overall form is:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Candidate score = Goal relevance + Graph structural relevance - Historical repetition penalty</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>This scoring doesn&#39;t replace the LLM&#39;s final decision — it surfaces more promising candidates first, then lets the LLM reason based on the problem, state, and historical trajectory.</p><h2 id="_08-why-must-it-be-a-closed-loop-instead-of-generating-the-full-proof-at-once" tabindex="-1"><a class="header-anchor" href="#_08-why-must-it-be-a-closed-loop-instead-of-generating-the-full-proof-at-once"><span>08. Why Must It Be a Closed Loop Instead of Generating the Full Proof at Once?</span></a></h2><p>The authors also designed a Single-pass version.</p><p>It still has the query-adaptive TPG, but requires the LLM to generate the complete theorem sequence at once, with the symbolic executor only verifying at the end.</p><p>Results:</p><table><thead><tr><th>Method</th><th>Overall</th><th>Easy</th><th>Medium</th><th>Hard</th></tr></thead><tbody><tr><td>Vanilla ICL</td><td>26.3</td><td>39.7</td><td>6.9</td><td>0.0</td></tr><tr><td>Single-pass</td><td>34.3</td><td>53.3</td><td>5.7</td><td>0.0</td></tr><tr><td>Pri-TPG</td><td>84.3</td><td>96.1</td><td>73.0</td><td>41.0</td></tr></tbody></table><p>Even with structural priors, Single-pass scores 0 on Hard tasks.</p><p>This shows that one-shot planning cannot handle errors that occur mid-proof in long chains.</p><table><thead><tr><th>Single-pass</th><th>Iterative Pri-TPG</th></tr></thead><tbody><tr><td>Generates the full sequence at once</td><td>Selects one step at a time</td></tr><tr><td>Unified verification at the end</td><td>Immediate verification after each step</td></tr><tr><td>Cannot correct mid-proof</td><td>Can re-plan based on feedback</td></tr><tr><td>Errors accumulate along the chain</td><td>Errors are截断 in time</td></tr><tr><td>Long tasks容易 collapse</td><td>Medium-to-long tasks are significantly more stable</td></tr></tbody></table><p>Formal reasoning must be a closed loop:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>Plan</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Execute</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Feedback</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Correct</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="/images/pri-tpg/singlepass-vs-iterative.png" alt="" tabindex="0" loading="lazy" width="1639" height="883"><figcaption></figcaption></figure><p><em>Single-pass scores 0 on Hard tasks even with query-adaptive prior; step-by-step symbolic feedback is critical for medium-to-long proofs.</em></p><p>One-sentence summary:</p><blockquote><p><strong>The graph structure solves &quot;where to go,&quot; symbolic feedback solves &quot;what to do after going wrong.&quot;</strong></p></blockquote><h2 id="_09-what-does-the-experiment-actually-prove" tabindex="-1"><a class="header-anchor" href="#_09-what-does-the-experiment-actually-prove"><span>09. What Does the Experiment Actually Prove?</span></a></h2><p>A proper close reading of experiments shouldn&#39;t just look at who scored higher.</p><p>More importantly:</p><blockquote><p>Which research hypothesis does each experiment validate?</p></blockquote><p>Pri-TPG&#39;s experiments form a clear chain of evidence.</p><h3 id="main-results" tabindex="-1"><a class="header-anchor" href="#main-results"><span>Main Results</span></a></h3><table><thead><tr><th>Method</th><th>Trained</th><th>Total</th><th>L1</th><th>L2</th><th>L3</th><th>L4</th><th>L5</th><th>L6</th></tr></thead><tbody><tr><td>Vanilla ICL (GPT-5 mini)</td><td>No</td><td>26.29</td><td>52.19</td><td>23.67</td><td>7.89</td><td>5.10</td><td>0.00</td><td>0.00</td></tr><tr><td>Pri-TPG (GPT-5 mini)</td><td>No</td><td>84.42</td><td>98.54</td><td>93.09</td><td>78.20</td><td>64.33</td><td>58.06</td><td>23.33</td></tr><tr><td>Pri-TPG (GPT-5.2)</td><td>No</td><td>89.29</td><td>99.16</td><td>96.28</td><td>87.92</td><td>77.07</td><td>66.13</td><td>30.00</td></tr><tr><td>FGeo-HyperGNet</td><td>Yes</td><td>88.36</td><td>96.24</td><td>91.76</td><td>87.59</td><td>82.17</td><td>56.45</td><td>56.67</td></tr></tbody></table><p>From the table:</p><ul><li>Pri-TPG performs strongly from L1 to L5;</li><li>Vanilla ICL rapidly collapses with increasing depth;</li><li>Pri-TPG still shows significant decline on L6;</li><li>Trained specialized models maintain advantages on extremely long chains.</li></ul><h3 id="evidence-chain-1-what-do-rag-and-tpg-each-contribute" tabindex="-1"><a class="header-anchor" href="#evidence-chain-1-what-do-rag-and-tpg-each-contribute"><span>Evidence Chain 1: What Do RAG and TPG Each Contribute?</span></a></h3><table><thead><tr><th>Setting</th><th>Iterative</th><th>RAG</th><th>TPG</th><th>Total</th><th>Hard</th></tr></thead><tbody><tr><td>Vanilla ICL</td><td>✓</td><td>✗</td><td>✗</td><td>26.29</td><td>0.00</td></tr><tr><td>w/o TPG</td><td>✓</td><td>✓</td><td>✗</td><td>72.64</td><td>22.95</td></tr><tr><td>Pri-TPG</td><td>✓</td><td>✓</td><td>✓</td><td>84.42</td><td>40.98</td></tr></tbody></table><p>This set of experiments shows:</p><table><thead><tr><th>Module</th><th>Main Contribution</th></tr></thead><tbody><tr><td>RAG</td><td>Narrows the candidate theorem range</td></tr><tr><td>TPG</td><td>Organizes theorem precedence</td></tr><tr><td>Iterative Feedback</td><td>Supports mid-course correction</td></tr></tbody></table><p>RAG improves performance from 26.29% to 72.64%, demonstrating the importance of candidate narrowing.</p><p>TPG further improves from 72.64% to 84.42%, showing:</p><blockquote><p>Finding relevant theorems doesn&#39;t mean knowing how to organize them.</p></blockquote><h3 id="evidence-chain-2-more-precise-structural-priors-→-better-results" tabindex="-1"><a class="header-anchor" href="#evidence-chain-2-more-precise-structural-priors-→-better-results"><span>Evidence Chain 2: More Precise Structural Priors → Better Results</span></a></h3><table><thead><tr><th>Setting</th><th>Total</th><th>Easy</th><th>Medium</th><th>Hard</th></tr></thead><tbody><tr><td>Vanilla ICL</td><td>26.29</td><td>39.65</td><td>6.86</td><td>0.00</td></tr><tr><td>Global Prior</td><td>29.71</td><td>40.70</td><td>14.89</td><td>4.10</td></tr><tr><td>Query-Adaptive Prior</td><td>58.43</td><td>72.40</td><td>41.61</td><td>18.85</td></tr><tr><td>State-Aware Pri-TPG</td><td>84.42</td><td>96.14</td><td>73.05</td><td>40.98</td></tr></tbody></table><p>These results show that using only the global graph provides limited help.</p><p>The real improvements come from:</p><ol><li>Making the structure relevant to the current problem;</li><li>Making the structure relevant to the current state.</li></ol><p>Thus, bigger structural priors aren&#39;t better — what matters is:</p><blockquote><p><strong>The closer they are to the current problem and current reasoning state, the better.</strong></p></blockquote><h3 id="evidence-chain-3-does-the-method-depend-on-a-specific-llm" tabindex="-1"><a class="header-anchor" href="#evidence-chain-3-does-the-method-depend-on-a-specific-llm"><span>Evidence Chain 3: Does the Method Depend on a Specific LLM?</span></a></h3><table><thead><tr><th>Backbone</th><th>Total</th><th>Easy</th><th>Medium</th><th>Hard</th></tr></thead><tbody><tr><td>DeepSeek v3.2</td><td>83.57</td><td>95.56</td><td>72.10</td><td>39.34</td></tr><tr><td>GPT-5 mini</td><td>84.42</td><td>96.14</td><td>73.00</td><td>40.98</td></tr><tr><td>Claude 4.5 Sonnet</td><td>87.07</td><td>97.31</td><td>77.54</td><td>48.36</td></tr><tr><td>Gemini 3.0 Pro</td><td>88.43</td><td>97.54</td><td>81.56</td><td>48.36</td></tr><tr><td>GPT-5.2</td><td>89.29</td><td>97.89</td><td>83.92</td><td>48.36</td></tr></tbody></table><p>Different models show different absolute scores, but all achieve strong results after integrating Pri-TPG.</p><p>This suggests that Pri-TPG is more like a pluggable external reasoning scaffold than a technique specific to any single model.</p><figure><img src="/images/pri-tpg/experiment-chain.png" alt="" tabindex="0" loading="lazy" width="1200" height="896"><figcaption></figcaption></figure><p><strong>Summary Card:</strong></p><blockquote><p>RAG solves &quot;what are the candidates,&quot; TPG solves &quot;how to organize candidates,&quot; Symbolic Feedback solves &quot;how to catch errors in time.&quot;</p></blockquote><h2 id="_10-how-should-89-29-be-properly-understood" tabindex="-1"><a class="header-anchor" href="#_10-how-should-89-29-be-properly-understood"><span>10. How Should 89.29% Be Properly Understood?</span></a></h2><p>89.29% is a strong result, but its evaluation boundary needs attention.</p><table><thead><tr><th>Evaluation Condition</th><th>Specific Setting</th></tr></thead><tbody><tr><td>Input format</td><td>Uses ground-truth formal inputs</td></tr><tr><td>Main evaluation focus</td><td>Theorem planning and symbolic search</td></tr><tr><td>Includes full auto-formalization</td><td>No</td></tr><tr><td>Time limit per problem</td><td>600 seconds</td></tr><tr><td>Max reasoning steps</td><td>20</td></tr><tr><td>Top-K retrieval size</td><td>200</td></tr><tr><td>Max recovery attempts</td><td>3</td></tr><tr><td>Multiple LLM calls</td><td>Yes</td></tr></tbody></table><p>To isolate &quot;reasoning and search ability,&quot; the paper provides correct formalized inputs directly to all methods.</p><p>That is, the system does not start from completely raw natural language and geometry images to independently complete the entire formalization process.</p><p>More precisely:</p><blockquote><p>89.29% mainly measures the system&#39;s ability to perform theorem planning and symbolic search given correct formalized representations.</p></blockquote><p>Therefore:</p><blockquote><p><strong>Training-free doesn&#39;t mean no cost, nor does it mean the end-to-end system is fully solved.</strong></p></blockquote><p>&quot;Non-parametric&quot; here doesn&#39;t mean the entire system has no parametric models either.</p><table><thead><tr><th>System still depends on</th><th>Exists?</th></tr></thead><tbody><tr><td>Pre-trained LLM</td><td>Yes</td></tr><tr><td>Multimodal Embedding model</td><td>Yes</td></tr><tr><td>Historical proof database</td><td>Yes</td></tr><tr><td>Additional gradient training for theorem prediction</td><td>No</td></tr></tbody></table><p>&quot;Non-parametric&quot; mainly means:</p><blockquote><p>The theorem prediction strategy isn&#39;t re-trained into model weights — it&#39;s provided as external retrieval graphs and structural priors at inference time.</p></blockquote><h2 id="_11-what-limitations-does-the-paper-explicitly-acknowledge" tabindex="-1"><a class="header-anchor" href="#_11-what-limitations-does-the-paper-explicitly-acknowledge"><span>11. What Limitations Does the Paper Explicitly Acknowledge?</span></a></h2><table><thead><tr><th>Limitation</th><th>Specific Manifestation</th></tr></thead><tbody><tr><td>Lower inference efficiency</td><td>Multi-step planning requires repeated LLM calls</td></tr><tr><td>Very long chains remain difficult</td><td>Significant accuracy drop on L6</td></tr><tr><td>TPG is local</td><td>Primarily encodes local precedence, not full global depth</td></tr><tr><td>Single-step errors have high impact</td><td>One failed step can破坏 the entire subsequent proof chain</td></tr><tr><td>Still relies on base model capability</td><td>Stronger backbones generally yield higher absolute performance</td></tr></tbody></table><p>These limitations show:</p><blockquote><p>Pri-TPG significantly mitigates local unstructured search, but hasn&#39;t fully solved global long-range consistency.</p></blockquote><h2 id="_12-my-further-analysis" tabindex="-1"><a class="header-anchor" href="#_12-my-further-analysis"><span>12. My Further Analysis</span></a></h2><p>The following questions aren&#39;t all explicitly raised by the paper, but are延伸 judgments based on its method design and experimental results.</p><h3 id="_1-is-tpg-a-logical-dependency-graph-or-an-empirical-order-graph" tabindex="-1"><a class="header-anchor" href="#_1-is-tpg-a-logical-dependency-graph-or-an-empirical-order-graph"><span>1. Is TPG a Logical Dependency Graph or an Empirical Order Graph?</span></a></h3><p>The paper describes edges (u \\rightarrow v) as prerequisite dependencies between theorems.</p><p>But the graph is primarily constructed from historical解题 trajectories.</p><table><thead><tr><th>Strict Logical Dependency</th><th>Historical Empirical Order</th></tr></thead><tbody><tr><td>A is a necessary prerequisite for B</td><td>A frequently appears before B</td></tr><tr><td>Strong causal implication</td><td>May just be data bias</td></tr><tr><td>More stable across datasets</td><td>May be influenced by proof style</td></tr><tr><td>Can be formally verified</td><td>May just be statistical co-occurrence</td></tr></tbody></table><p>A appearing before B in historical trajectories doesn&#39;t necessarily mean A is a strict necessary condition for B.</p><p>It could also be:</p><ul><li>A common proof convention in the dataset;</li><li>The training set prefers a certain proof route;</li><li>Other valid orders also exist;</li><li>The two theorems simply co-occur frequently.</li></ul><p>Thus, a question worth further investigation is:</p><blockquote><p>Does TPG learn causal dependencies or high-frequency path templates?</p></blockquote><h3 id="_2-local-structural-consistency-global-proof-consistency" tabindex="-1"><a class="header-anchor" href="#_2-local-structural-consistency-global-proof-consistency"><span>2. Local Structural Consistency ≠ Global Proof Consistency</span></a></h3><p>Pri-TPG primarily performs structural localization based on successors of the previous theorem.</p><table><thead><tr><th>Local Advantage</th><th>Potential Problem</th></tr></thead><tbody><tr><td>Maintains step-by-step coherence</td><td>May restrict cross-branch switches</td></tr><tr><td>Reduces无效 successors</td><td>May miss alternative proof routes</td></tr><tr><td>Reduces short-range search difficulty</td><td>Doesn&#39;t guarantee eventual goal reachability</td></tr><tr><td>Leverages historical local patterns</td><td>May struggle with backtracking</td></tr></tbody></table><p>Locally reasonable consecutive steps don&#39;t necessarily lead to the target.</p><p>This is also a key reason why very long chains like L6 remain difficult.</p><h3 id="_3-failure-affects-ranking-but-doesn-t-actually-update-the-graph" tabindex="-1"><a class="header-anchor" href="#_3-failure-affects-ranking-but-doesn-t-actually-update-the-graph"><span>3. Failure Affects Ranking but Doesn&#39;t Actually Update the Graph</span></a></h3><p>Pri-TPG applies history penalty to repeated and failed theorems.</p><p>But this mechanism mainly adjusts candidate ranking within the current推理.</p><table><thead><tr><th>Current Mechanism</th><th>Further Structure Learning</th></tr></thead><tbody><tr><td>Down-weights failed theorems</td><td>Locates the node or edge causing failure</td></tr><tr><td>Avoids repeated attempts</td><td>Updates the graph structure itself</td></tr><tr><td>Effective within the current task</td><td>Can accumulate经验 across tasks</td></tr><tr><td>Local ranking adjustment</td><td>Global credit assignment</td></tr></tbody></table><p>It hasn&#39;t yet truly achieved:</p><blockquote><p>Using a single failure to back-locate which node or edge in the graph is problematic, and updating the overall structure accordingly.</p></blockquote><h3 id="_4-high-recall-rate-vs-reasoning-cost-a-continuing-tension" tabindex="-1"><a class="header-anchor" href="#_4-high-recall-rate-vs-reasoning-cost-a-continuing-tension"><span>4. High Recall Rate vs. Reasoning Cost: A Continuing Tension</span></a></h3><p>Experiments show that larger K yields higher accuracy, especially on medium-to-hard tasks.</p><table><thead><tr><th>Larger K</th><th>Smaller K</th></tr></thead><tbody><tr><td>Less likely to miss critical theorems</td><td>Lower retrieval cost</td></tr><tr><td>Higher candidate coverage</td><td>More compact candidate set</td></tr><tr><td>More reliable for long chains</td><td>More likely to miss key theorems</td></tr><tr><td>Greater subsequent ranking pressure</td><td>Higher requirement on retrieval quality</td></tr></tbody></table><p>Balancing:</p><ul><li>Smaller retrieval scale;</li><li>Lower invocation cost;</li><li>Higher recall of critical theorems</li></ul><p>remains both an engineering and research challenge.</p><h2 id="_13-from-pri-tpg-to-dynamic-self-evolving-tpg" tabindex="-1"><a class="header-anchor" href="#_13-from-pri-tpg-to-dynamic-self-evolving-tpg"><span>13. From Pri-TPG to Dynamic Self-Evolving TPG</span></a></h2><p>Pri-TPG currently solves:</p><blockquote><p>How to extract local structural priors from historical successful trajectories to help LLMs narrow the search space.</p></blockquote><p>But it hasn&#39;t fully solved:</p><blockquote><p>After a reasoning failure, how to localize the error and update the global graph structure?</p></blockquote><p>A natural follow-up direction is:</p><h3 id="dynamic-self-evolving-tpg" tabindex="-1"><a class="header-anchor" href="#dynamic-self-evolving-tpg"><span>Dynamic Self-Evolving TPG</span></a></h3><p>That is:</p><blockquote><p>Using both successful and failed trajectories to enable the theorem precedence graph to continuously update during inference.</p></blockquote><h3 id="pri-tpg-vs-dynamic-tpg" tabindex="-1"><a class="header-anchor" href="#pri-tpg-vs-dynamic-tpg"><span>Pri-TPG vs. Dynamic TPG</span></a></h3><table><thead><tr><th>Dimension</th><th>Pri-TPG</th><th>Dynamic Self-Evolving TPG</th></tr></thead><tbody><tr><td>Main data source</td><td>Historical successful trajectories</td><td>Successful + failed trajectories</td></tr><tr><td>Graph state</td><td>Built during inference, structure mainly from history</td><td>Continuously updated during current inference</td></tr><tr><td>Failure handling</td><td>Down-weights failed actions</td><td>Credit assignment across nodes, edges, and subpaths</td></tr><tr><td>Search method</td><td>Local structure guidance</td><td>Local guidance + global backtracking</td></tr><tr><td>Learning goal</td><td>Avoid unstructured exploration</td><td>Learn to correct erroneous structures</td></tr><tr><td>Global consistency</td><td>Limited</td><td>Core optimization target</td></tr></tbody></table><p>A possible process:</p><div class="language-text line-numbers-mode" data-highlighter="shiki" data-ext="text" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code class="language-text"><span class="line"><span>LLM reasons along the current TPG</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Symbolic executor detects path failure or goal unreachable</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Locate the node or edge that first made subsequent completion impossible</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Perform backward credit assignment on the relevant local structure</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Lower erroneous edge weights, raise alternative path weights</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Update the TPG</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Re-plan</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The corresponding research question can be formulated as:</p><blockquote><p>Can an LLM agent use failed reasoning trajectories to perform backward credit assignment over a theorem precedence graph, thereby improving global consistency in long-horizon theorem proving?</p></blockquote><p>Further exploration directions:</p><table><thead><tr><th>Direction</th><th>Potential Role</th></tr></thead><tbody><tr><td>Tree-search-based global backtracking</td><td>Switch to alternative branches after failure</td></tr><tr><td>Value propagation on the graph</td><td>Back-propagate final outcomes to nodes and edges</td></tr><tr><td>Node-level credit assignment</td><td>Determine which theorem choice was critical</td></tr><tr><td>Edge-level credit assignment</td><td>Determine which theorem transition was unreliable</td></tr><tr><td>Joint modeling of success and failure trajectories</td><td>Learn both what to do and what not to do</td></tr><tr><td>Uncertainty-driven expansion</td><td>Broaden search at high-uncertainty positions</td></tr><tr><td>Hierarchical or hypergraph</td><td>Express more complex multi-theorem dependencies</td></tr></tbody></table><figure><img src="/images/pri-tpg/self-evolving.png" alt="" tabindex="0" loading="lazy" width="1200" height="896"><figcaption></figcaption></figure><p><em>Perhaps the true next step isn&#39;t building larger static reasoning graphs, but enabling graphs to self-correct from failures.</em></p><h2 id="_14-conclusion-from-content-augmentation-to-structure-augmentation" tabindex="-1"><a class="header-anchor" href="#_14-conclusion-from-content-augmentation-to-structure-augmentation"><span>14. Conclusion: From Content Augmentation to Structure Augmentation</span></a></h2><p>Pri-TPG appears on the surface to be a geometry theorem prediction paper.</p><p>But the idea it truly conveys is:</p><blockquote><p>LLM reasoning failures sometimes aren&#39;t because the model doesn&#39;t know the answer, but because it faces an action space that&#39;s too large without stable structural navigation.</p></blockquote><p>This paper addresses the problem through three mechanisms:</p><table><thead><tr><th>Module</th><th>Problem Solved</th></tr></thead><tbody><tr><td>RAG</td><td>Find theorems relevant to the current problem</td></tr><tr><td>TPG</td><td>Organize precedence relationships between these theorems</td></tr><tr><td>Symbolic Feedback</td><td>Verify, update, and re-plan after each step</td></tr></tbody></table><p>It transforms the LLM from a free generator into a structurally constrained high-level planner.</p><p>The core shift can be summarized as:</p><table><thead><tr><th>Past</th><th>Direction Represented by Pri-TPG</th></tr></thead><tbody><tr><td>Retrieve knowledge</td><td>Retrieve structure</td></tr><tr><td>One-shot generation</td><td>Closed-loop execution</td></tr><tr><td>Unconstrained reasoning</td><td>Structured search</td></tr><tr><td>Only leverages successful examples</td><td>Future: leverage both success and failure feedback</td></tr><tr><td>Internal model memory strategy</td><td>External interpretable structural prior</td></tr></tbody></table><p>Of course, Pri-TPG still primarily solves local theorem ordering.</p><p>For extremely long proofs, it still faces:</p><table><thead><tr><th>Unresolved Issues</th><th>Manifestation</th></tr></thead><tbody><tr><td>Insufficient global consistency</td><td>Significant performance drop on L6</td></tr><tr><td>Limited backtracking ability</td><td>Mainly relies on local successors</td></tr><tr><td>Inadequate use of failure information</td><td>Only down-weights, doesn&#39;t update the graph</td></tr><tr><td>High reasoning cost</td><td>Multiple LLM calls and large-scale retrieval</td></tr></tbody></table><p>But this precisely shows that this paper isn&#39;t an end point, but an excellent starting point.</p><p>Future long-horizon Agents may need not only stronger models, larger contexts, and more tools, but also a self-evolving reasoning system capable of:</p><blockquote><p><strong>Extracting structure from history, validating structure during execution, and updating structure from failure.</strong></p></blockquote><p>And that may be the most值得 pursuing question that Pri-TPG leaves for Agent research.</p>`,250)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};